import React from 'react';
import { Carousel } from 'react-responsive-carousel';
import 'react-responsive-carousel/lib/styles/carousel.min.css';
import { Card } from 'antd';

interface AntdCarouselProps {
  items: React.ReactNode[];
}

const AntdCarousel: React.FC<AntdCarouselProps> = ({ items }) => {
  return (
    <Carousel showThumbs={false} showArrows={true} infiniteLoop={true}>
      {items.map((item, index) => (
        <Card key={index} style={{ width: 300, margin: 'auto' }}>
          {item}
        </Card>
      ))}
    </Carousel>
  );
};

export default AntdCarousel;
